TRANS_PATH = os.path.join(SCRIPT_DIR, 'az104_en_translations.json')

with open(TRANS_PATH) as f:
    en = json.load(f)

# Add storage-010 through storage-020
en['storage-010.question'] = 'How long are deleted blobs retained by default with Soft Delete?'
en['storage-010.option_a'] = '1 day'
en['storage-010.option_b'] = '7 days'
en['storage-010.option_c'] = '30 days'
en['storage-010.option_d'] = '365 days'
en['storage-010.explanation'] = '**Blob Soft Delete** has a default retention of **7 days** (configurable from 1 to 365 days).\n\n**How it works:**\n- Deleted blobs remain in the Storage Account\n- Can be recovered within the retention period\n- The deletion itself is not permanent until the retention period expires\n\n**Configuration:**\n- Default: 7 days\n- Minimum: 1 day\n- Maximum: 365 days\n\n*Exam tip*: Soft Delete is for blob recovery. Enable it to protect against accidental deletions.'

en['storage-011.question'] = 'Which Immutable Storage Policy can NOT be removed once committed?'
en['storage-011.option_a'] = 'Time-based Retention Policy (unlocked)'
en['storage-011.option_b'] = 'Time-based Retention Policy (locked)'
en['storage-011.option_c'] = 'Legal Hold Policy'
en['storage-011.option_d'] = 'Version-level Immutability'
en['storage-011.explanation'] = 'A **locked Time-based Retention Policy** cannot be *removed* after commit.\n\n**Immutable Storage Policy types:**\n\n**Time-based (unlocked):**\n- Removable after lock: Yes\n- Use: Testing, temporary retention\n\n**Time-based (locked):**\n- Removable after lock: **No - permanent**\n- Use: Compliance (SEC 17a-4, FINRA rules)\n- The lock period cannot be shortened (only extended)\n\n**Legal Hold Policy:**\n- Removable: Yes (explicitly remove the hold)\n- Use: Litigation hold\n\n*Exam tip*: Locked immutable policies are COMPLIANCE-grade - they CANNOT be reversed. Think carefully before locking!'

en['storage-012.question'] = 'Which features does Azure Data Lake Storage Gen2 add beyond standard Blob Storage? (Select 2)'
en['storage-012.option_a'] = 'Hierarchical Namespace'
en['storage-012.option_b'] = 'POSIX-compliant ACLs'
en['storage-012.option_c'] = 'Hot/Cool/Archive Tiers'
en['storage-012.option_d'] = 'GRS Replication'
en['storage-012.explanation'] = '**Azure Data Lake Storage Gen2** extends Blob Storage with two key features:\n\n1. **Hierarchical Namespace (HNS):**\n   - True directory structures (not just prefixes)\n   - Atomic directory operations (rename, delete)\n   - Up to 10x better performance for directory-heavy workloads\n\n2. **POSIX-compliant ACLs:**\n   - Fine-grained Unix-style permissions\n   - Read (r), Write (w), Execute (x)\n   - Default ACLs for inheritance\n\n**Already in standard Blob Storage:**\n- Hot/Cool/Archive Tiers\n- GRS and other replication options\n\n*Exam tip*: ADLS Gen2 = Blob Storage + HNS + POSIX ACLs. Tier/replication are standard Blob features, not ADLS-specific.'

en['storage-013.question'] = 'What happens when you enable Storage Account Firewall Rules without Allow-Rules?'
en['storage-013.option_a'] = 'Only access via Private Endpoints'
en['storage-013.option_b'] = 'All access is blocked (including Azure Portal)'
en['storage-013.option_c'] = 'Only Azure Services can access'
en['storage-013.option_d'] = 'No change, everyone can access'
en['storage-013.explanation'] = 'When the **Storage Firewall** is enabled ("Selected networks") without explicit Allow-Rules, *all access is blocked* - including the Azure Portal.\n\n**Consequences:**\n- No access to blobs/files/tables/queues\n- Azure Portal access is blocked\n- Azure CLI and PowerShell cannot access\n- Only traffic explicitly allowed by rules can reach the storage\n\n**To restore access, you need:**\n- **IP rules**: Allow specific IP ranges\n- **VNet rules**: Allow specific VNets/Subnets\n- **Resource exceptions**: Allow trusted Azure services\n- **Private Endpoints**: Add private endpoints for controlled access\n\n*Exam tip*: Enabling the firewall without rules blocks EVERYTHING. Always add management access rules first!'

en['storage-014.question'] = 'What is the Azure Import/Export Service used for?'
en['storage-014.option_a'] = 'Fast migration of large data volumes via physical disks'
en['storage-014.option_b'] = 'Automatic backup of VMs'
en['storage-014.option_c'] = 'Synchronization between on-premises and cloud'
en['storage-014.option_d'] = 'Replication between Storage Accounts'
en['storage-014.explanation'] = 'The **Azure Import/Export Service** enables migration of very large data volumes (multiple TB) by shipping physical hard drives.\n\n**Process:**\n1. Copy data to SATA HDDs/SSDs and encrypt with **BitLocker**\n2. Ship drives to an Azure datacenter\n3. Azure imports data directly to Storage\n\n**Ideal for:**\n- Multi-TB data migrations\n- Slow or unreliable network connections\n- First-time data seeding into Azure\n\n**Alternative for smaller volumes:**\n- AzCopy (network-based)\n- Azure Data Box (for ~TB-scale where network is insufficient)\n\n*Exam tip*: Import/Export = physical disk shipping for very large data. Data Box is the managed appliance alternative.'

en['storage-015.question'] = 'Which protocol is primarily used by Azure NetApp Files?'
en['storage-015.option_a'] = 'SMB 3.0'
en['storage-015.option_b'] = 'NFS v3 and v4.1'
en['storage-015.option_c'] = 'iSCSI'
en['storage-015.option_d'] = 'FTP'
en['storage-015.explanation'] = '**Azure NetApp Files** primarily supports **NFS v3 and NFSv4.1** (as well as SMB for Windows workloads).\n\n**Properties:**\n- Enterprise-grade File Storage Service\n- Extreme performance: up to 4.5 GB/s throughput\n- Sub-millisecond latency\n\n**Supported protocols:**\n- **NFS v3**: Legacy NFS, widely supported\n- **NFS v4.1**: Modern NFS with locking, ACLs\n- **SMB 3.0**: Windows file sharing (dual-protocol possible)\n\n**Use cases:**\n- HPC workloads\n- SAP and database workloads\n- Linux-based file shares\n\n*Exam tip*: Azure NetApp Files = high-performance NFS (and SMB). Not standard storage - it runs on NetApp hardware in Azure datacenters.'

en['storage-016.question'] = 'How long are Storage Analytics Metrics retained by default?'
en['storage-016.option_a'] = '7 days'
en['storage-016.option_b'] = '30 days'
en['storage-016.option_c'] = '90 days'
en['storage-016.option_d'] = '1 year'
en['storage-016.explanation'] = '**Storage Analytics Metrics** (Classic Metrics) are retained for **7 days** and then automatically deleted.\n\n**For longer retention:**\n- Use **Azure Monitor Metrics** instead\n- Route via Diagnostic Settings\n- Standard Azure Monitor retention: 93 days\n\n**Why 7 days?**\n- Classic metrics are stored in $logs container\n- They are meant for short-term debugging\n- For production monitoring, always use Azure Monitor\n\n*Exam tip*: Classic Storage Metrics = 7 days. For longer retention, use Azure Monitor Metrics with Diagnostic Settings.'

en['storage-017.question'] = 'What is Azure Blob Inventory used for?'
en['storage-017.option_a'] = 'Automatic Lifecycle Management'
en['storage-017.option_b'] = 'Daily reports on blob metadata and properties'
en['storage-017.option_c'] = 'Blob Replication between regions'
en['storage-017.option_d'] = 'Blob Access Logging'
en['storage-017.explanation'] = '**Azure Blob Inventory** generates daily reports on blob metadata and properties.\n\n**Report contents:**\n- Name, Size, Access Tier\n- Encryption Status\n- Tags, Timestamps\n- Blob Type, Content Type\n\n**Use cases:**\n- **Compliance audits**: e.g., "Are all blobs encrypted?"\n- **Cost analysis**: Tier distribution analysis\n- **Data Lifecycle Governance**: Overview of data aging\n\n**Configuration:**\n- Inventory Rules define container scope\n- Export format: CSV or Parquet\n- Reports are stored as blobs\n\n*Exam tip*: Blob Inventory is cheaper and more efficient than List APIs for large-scale analysis.'

en['storage-018.question'] = 'What is the main difference between GRS and Object Replication?'
en['storage-018.option_a'] = 'GRS is synchronous, Object Replication is asynchronous'
en['storage-018.option_b'] = 'GRS replicates all blobs automatically, Object Replication only selected containers'
en['storage-018.option_c'] = 'GRS is cheaper'
en['storage-018.option_d'] = 'Object Replication supports Cross-Subscription'
en['storage-018.explanation'] = 'The main difference between **GRS** and **Object Replication**:\n\n**GRS (Geo-Redundant Storage):**\n- Replicates *all* data of a Storage Account automatically\n- To the Paired Region (fixed, not configurable)\n- Secondary is Read-Only (except during failover)\n\n**Object Replication:**\n- Granular, *policy-based* replication\n- Only *selected containers* are replicated\n- To *any* Storage Account (also Cross-Subscription, Cross-Region)\n- Both sides can be Read/Write\n\n**Use cases for Object Replication:**\n- Data sovereignty (only specific data in region X)\n- Minimize latency (data closer to users)\n- Custom backup strategies\n\n*Important*: Object Replication requires **Versioning** on both source and destination.'

en['storage-019.question'] = 'What is the best practice for Storage Account Key Rotation?'
en['storage-019.option_a'] = 'Regenerate both keys simultaneously'
en['storage-019.option_b'] = 'Regenerate Key1, then Key2 after application update'
en['storage-019.option_c'] = 'Never regenerate keys'
en['storage-019.option_d'] = 'Automatically rotate keys monthly'
en['storage-019.explanation'] = '**Best practice for Storage Account Key Rotation:**\n\n**Recommended process:**\n1. All applications use **Key1**\n2. **Regenerate Key2** (Key1 remains valid)\n3. Switch applications to **Key2**\n4. **Regenerate Key1**\n\nThis process minimizes downtime since a valid key is always available.\n\n**What to avoid:**\n- *Never* regenerate both keys simultaneously (breaks all access immediately!)\n\n**Better alternatives:**\n- Use **Shared Access Signatures (SAS)** with expiration instead of account keys\n- Switch entirely to **Entra ID Authentication** (Managed Identities, RBAC)\n- Deactivate account keys after migration\n\n*Exam tip*: Azure Key Vault can be used for secure key storage and automatic rotation.'

en['storage-020.question'] = 'Which Managed Disk Types offer SSD performance? (Select 3)'
en['storage-020.option_a'] = 'Standard HDD'
en['storage-020.option_b'] = 'Standard SSD'
en['storage-020.option_c'] = 'Premium SSD'
en['storage-020.option_d'] = 'Ultra Disk'
en['storage-020.option_e'] = 'Premium HDD'
en['storage-020.explanation'] = '**Azure Managed Disk Types** with SSD performance:\n\n**Standard SSD:**\n- SSD technology\n- Up to 6,000 IOPS\n- Medium latency\n- For production with moderate requirements\n\n**Premium SSD:**\n- SSD technology\n- Up to 20,000 IOPS\n- Low latency\n- For production VMs, databases\n\n**Ultra Disk:**\n- SSD technology\n- Up to 160,000 IOPS\n- Sub-millisecond latency\n- For SAP HANA, transaction-intensive DBs\n\n**Not SSD:**\n- **Standard HDD**: For dev/test, backup (cheapest option)\n- *Premium HDD does not exist*\n\n**Requirements:**\n- Premium SSD and Ultra Disk require VM sizes with "s" (e.g., D4s_v5)\n- Ultra Disk only available in certain regions/zones\n\n*Exam tip*: For databases with high IOPS requirements, **Ultra Disk** is the best choice.'

# compute-010 through compute-025
en['compute-010.question'] = 'What are Proximity Placement Groups used for?'
en['compute-010.option_a'] = 'Distributing VMs across multiple Availability Zones'
en['compute-010.option_b'] = 'Placing VMs physically close together for low latency'
en['compute-010.option_c'] = 'Automatically scaling VMs'
en['compute-010.option_d'] = 'Organizing VMs into different Resource Groups'
en['compute-010.explanation'] = '**Proximity Placement Groups (PPG)** place VMs *physically close together* in the same Azure datacenter.\n\n**Purpose:**\n- Minimizes network latency between VMs (< 1ms)\n- Optimized for latency-sensitive workloads\n\n**Ideal use cases:**\n- HPC clusters with high inter-node traffic\n- Databases with replication\n- Latency-sensitive gaming servers\n\n**Tradeoffs:**\n- *Reduces availability* (all VMs in same datacenter)\n- Should be *combined with Availability Sets* (for fault/update domain separation)\n- *Not compatible* with Availability Zones\n\n*Exam tip*: PPG = low latency, but availability tradeoffs. For high availability → Availability Zones.'

en['compute-011.question'] = 'What is the main advantage of Azure Dedicated Hosts?'
en['compute-011.option_a'] = 'Lower costs through sharing'
en['compute-011.option_b'] = 'Dedicated physical servers for compliance/licensing'
en['compute-011.option_c'] = 'Automatic scaling'
en['compute-011.option_d'] = 'Higher VM performance'
en['compute-011.explanation'] = '**Azure Dedicated Hosts** provide *dedicated physical servers* where only your VMs run.\n\n**Main advantages:**\n\n1. **Compliance:**\n   - Hardware isolation for regulated workloads\n   - Healthcare, Government, Financial Services\n\n2. **Licensing:**\n   - **Bring-Your-Own-License (BYOL)** for Windows Server/SQL Server\n   - Host-based licensing can save costs\n\n3. **Control:**\n   - Influence over maintenance events\n   - VM placement on specific hosts\n\n**Disadvantages:**\n- *Significantly more expensive* than shared infrastructure\n- Performance is *comparable* to standard VMs (no performance benefit)\n\n*Exam tip*: Dedicated Hosts for compliance or licensing optimization at scale.'

en['compute-012.question'] = 'Which statement about Azure Spot VMs is correct?'
en['compute-012.option_a'] = 'Spot VMs have a 99.9% SLA'
en['compute-012.option_b'] = 'Spot VMs can be evicted at any time with 30 seconds notice'
en['compute-012.option_c'] = 'Spot VMs are only available for Linux'
en['compute-012.option_d'] = 'Spot VMs offer 50% discount'
en['compute-012.explanation'] = '**Azure Spot VMs** - key properties:\n\n**Facts:**\n- Use unused Azure capacity\n- Up to **90% discount** compared to Pay-as-you-go\n- Can be *evicted at any time* (with **30 seconds notice**)\n- Support Windows *and* Linux\n\n**No SLA:**\n- Spot VMs have *no* availability SLA\n- Not suitable for production workloads\n\n**Ideal use cases:**\n- Batch Processing\n- Dev/Test environments\n- Rendering Jobs\n- Big Data Analysis\n\n**Eviction Policy:**\n- *Deallocate* (default): VM is stopped\n- *Delete*: VM is deleted\n\n*Exam tip*: Spot VMs ideal for *interruptible* workloads. For production → Reserved Instances or Pay-as-you-go.'

en['compute-013.question'] = 'Which caching mode is recommended by default for OS Disks?'
en['compute-013.option_a'] = 'None'
en['compute-013.option_b'] = 'Read-Only'
en['compute-013.option_c'] = 'Read/Write'
en['compute-013.option_d'] = 'Write-Through'
en['compute-013.explanation'] = '**VM Disk Caching** - recommended modes:\n\n**OS Disk:**\n- Recommended: **Read/Write** (default)\n- Improves boot times and OS performance\n\n**Data Disk (Read-heavy):**\n- Recommended: Read-Only\n\n**Data Disk (Database):**\n- Recommended: None\n- Prevents data loss on cache failure\n\n**Read/Write Caching:**\n- Uses VM-local SSDs for caching\n- Writes are confirmed to disk after flush (Write-Back)\n\n**Free:**\n- Host caching incurs *no* additional IOPS/throughput costs\n\n*Exam tip*: Ultra Disks only support "None" as caching mode.'

en['compute-014.question'] = 'What is the Custom Script Extension used for?'
en['compute-014.option_a'] = 'Automatic backups'
en['compute-014.option_b'] = 'Post-deployment configuration and software installation'
en['compute-014.option_c'] = 'Network monitoring'
en['compute-014.option_d'] = 'VM scaling'
en['compute-014.explanation'] = 'The **Custom Script Extension (CSE)** runs scripts on VMs after deployment.\n\n**Typical use cases:**\n- Post-deployment configuration\n- Software installation\n- Application deployment\n- Initial system configuration\n\n**Script sources:**\n- Azure Storage Blobs\n- GitHub\n- Inline in ARM Template\n\n**Supported script types:**\n- **Windows**: PowerShell, Batch\n- **Linux**: Bash, Python\n\n**Properties:**\n- Runs *once* after VM creation\n- Deploy via ARM Templates, Azure CLI, or Portal\n\n*Exam tip*: For more complex configuration management → **Azure Automation DSC** or **Ansible**.'

en['compute-015.question'] = 'What happens during a VM Resize to a different VM family (e.g., D-Series to E-Series)?'
en['compute-015.option_a'] = 'VM is automatically migrated without downtime'
en['compute-015.option_b'] = 'VM must be deallocated and restarted'
en['compute-015.option_c'] = 'Only CPU/Memory are adjusted'
en['compute-015.option_d'] = 'Resize is not possible'
en['compute-015.explanation'] = 'For a **VM Resize to a different VM family** (e.g., D-Series → E-Series):\n\n**Required steps:**\n1. VM must be **deallocated** (Stop + Release)\n2. VM is migrated to *new hardware*\n3. VM must be restarted\n\n**Consequences:**\n- **Downtime** required\n- *Dynamic IPs* are lost (Static IPs remain)\n- Availability Set VMs: All VMs in the set must support the target size\n\n**Resize within the same family:**\n- e.g., D2s_v5 → D4s_v5\n- *Sometimes* possible without deallocation\n- Not guaranteed - depends on cluster capacity\n\n*Best Practice*: Plan resize during maintenance windows. For critical workloads, use Load Balancer for blue-green deployment.'

en['compute-016.question'] = 'What is the main advantage of App Service Deployment Slots?'
en['compute-016.option_a'] = 'Lower costs through resource sharing'
en['compute-016.option_b'] = 'Zero-downtime deployments with Slot Swap'
en['compute-016.option_c'] = 'Automatic scaling'
en['compute-016.option_d'] = 'Free SSL certificates'
en['compute-016.explanation'] = '**App Service Deployment Slots** enable **zero-downtime blue-green deployments**.\n\n**Workflow:**\n1. Deploy new version to **Staging Slot**\n2. Test staging slot (has its own URL: `app-staging.azurewebsites.net`)\n3. **Swap** staging and production slots\n4. Traffic seamlessly moves to the new version\n\n**Swap features:**\n- **Auto-swap**: Automatically swap on successful deployment\n- **Slot-specific settings**: Connection strings, environment variables (marked as "slot settings")\n- **Traffic routing**: Route % of traffic to staging for A/B testing (Premium+)\n\n**Benefits:**\n- No downtime\n- Instant rollback (swap back)\n- Warm-up requests are sent to the new slot (pre-warming)\n\n*Exam tip*: Deployment Slots = Standard+ feature. Use for zero-downtime deployments.'

en['compute-017.question'] = 'What license requirement applies for Azure Hybrid Benefit (Windows Server)?'
en['compute-017.option_a'] = 'Windows Server Standard without Software Assurance'
en['compute-017.option_b'] = 'Windows Server with Software Assurance or Subscription'
en['compute-017.option_c'] = 'Windows 10 Pro license'
en['compute-017.option_d'] = 'Office 365 Subscription'
en['compute-017.explanation'] = '**Azure Hybrid Benefit (AHB)** for Windows Server requires licenses with **Software Assurance** (or equivalent subscriptions).\n\n**License requirements:**\n- Windows Server Datacenter or Standard\n- Must have active **Software Assurance** (SA)\n- Or equivalent subscription license\n\n**Cost savings:**\n- Up to 40% savings on Windows Server VMs\n- No license fee for Azure (you use existing on-premises licenses)\n- Each 2-core license covers up to 8 vCPU in Azure\n\n**Limitations:**\n- Cannot be used with Bring-Your-Own-License (BYOL) at the same time\n- Must be enabled per VM or at host level (Dedicated Host)\n\n*Exam tip*: AHB = Software Assurance required. Saves Windows Server licensing costs in Azure.'

en['compute-018.question'] = 'Which Azure Container Registry SKU offers Geo-Replication?'
en['compute-018.option_a'] = 'Basic'
en['compute-018.option_b'] = 'Standard'
en['compute-018.option_c'] = 'Premium'
en['compute-018.option_d'] = 'All SKUs'
en['compute-018.explanation'] = '**Azure Container Registry (ACR)** SKUs:\n\n**Basic SKU:**\n- Storage: 10 GB included\n- No Geo-Replication\n- No Private Link\n- For Dev/Test\n\n**Standard SKU:**\n- Storage: 100 GB included\n- No Geo-Replication\n- No Private Link\n- For production (single region)\n\n**Premium SKU:**\n- Storage: 500 GB included\n- **Geo-Replication** ✓\n- **Private Link** ✓\n- For global, multi-region deployments\n\n*Exam tip*: Only **Premium SKU** supports Geo-Replication and Private Link. Choose Premium for multi-region container deployments.'

en['compute-019.question'] = 'What commitment durations are available for Azure Reserved Instances?'
en['compute-019.option_a'] = '6 months'
en['compute-019.option_b'] = '1 year or 3 years'
en['compute-019.option_c'] = '2 years'
en['compute-019.option_d'] = '5 years'
en['compute-019.explanation'] = '**Azure Reserved Instances (RI)** offer two commitment durations:\n\n**Available commitment options:**\n- **1 year**: Moderate discount\n- **3 years**: Highest discount (up to 72% vs Pay-as-you-go)\n\n**Payment options:**\n- **Upfront**: Highest discount (pay everything at once)\n- **Monthly**: Moderate discount (pay monthly without interest)\n\n**Scope:**\n- Single subscription scope\n- Shared scope (across multiple subscriptions in the billing account)\n- Management group scope\n\n**Additional benefits:**\n- Reserved capacity in a specific region\n- Azure Hybrid Benefit can be stacked\n\n*Exam tip*: 1 year or 3 years commitment. 3 years gives the best discount. Payment can be upfront or monthly.'

en['compute-020.question'] = 'What is the difference between Generalized and Specialized VM Images?'
en['compute-020.option_a'] = 'Generalized Images are encrypted, Specialized are not'
en['compute-020.option_b'] = 'Generalized Images have no machine-specific info, Specialized retain it'
en['compute-020.option_c'] = 'Specialized Images are faster'
en['compute-020.option_d'] = 'There is no difference'
en['compute-020.explanation'] = 'The difference between **Generalized** and **Specialized** VM Images:\n\n**Generalized Images:**\n- Machine-specific info has been *removed* (Computer Name, Admin Accounts, SIDs)\n- Created via **Sysprep** (Windows) or **waagent -deprovision** (Linux)\n- Allows multiple VM deployments without conflicts\n- Can be used for VM Scale Sets\n\n**Specialized Images:**\n- Machine-specific info is *preserved*\n- All settings, users, applications remain\n- Cannot be modified after creation\n- Limited to single VM deployment\n\n**When to use which:**\n- Generalized: Mass deployments, Scale Sets, Gold Images\n- Specialized: Migration of existing machines, DR recovery\n\n*Exam tip*: Generalized = Sysprep/deprovisioned (mass deployment). Specialized = exact copy (migration/DR).'

# network-010 through network-020
en['network-010.question'] = 'Is VNet Peering transitive (can VNet A communicate with VNet C via VNet B)?'
en['network-010.option_a'] = 'Yes, automatically transitive'
en['network-010.option_b'] = 'No, peering is not transitive'
en['network-010.option_c'] = 'Only within the same region'
en['network-010.option_d'] = 'Only with Premium Peering'
en['network-010.explanation'] = '**VNet Peering is NOT transitive.**\n\n**Example:**\n- VNet A ↔ VNet B (peered)\n- VNet B ↔ VNet C (peered)\n- VNet A ↔ VNet C: *No direct communication possible*\n\n**For transitivity:**\n- Use explicit peering between all VNets (full mesh)\n- Or use Azure Virtual WAN (hub-and-spoke with transitive routing)\n- Or use a Hub VNet with an NVA acting as router\n\n**Characteristics:**\n- Low latency, high bandwidth (Azure backbone)\n- Cross-region possible (Global VNet Peering)\n- No downtime during peering creation\n\n*Exam tip*: VNet Peering = NOT transitive (unless you build a full mesh or use VPN Gateway/Virtual WAN).'

en['network-011.question'] = 'Which Next Hop Type in User-Defined Routes (UDR) routes traffic to an NVA?'
en['network-011.option_a'] = 'VirtualNetworkGateway'
en['network-011.option_b'] = 'Internet'
en['network-011.option_c'] = 'VirtualAppliance'
en['network-011.option_d'] = 'VnetLocal'
en['network-011.explanation'] = 'The **Next Hop Type "VirtualAppliance"** in User-Defined Routes (UDR) routes traffic to a Network Virtual Appliance (NVA).\n\n**Next Hop Types:**\n- **VirtualAppliance**: Network Virtual Appliance (Firewall, Router)\n- **VirtualNetworkGateway**: Routes to VPN/ExpressRoute Gateway\n- **VnetLocal**: Within the VNet (default)\n- **Internet**: Default internet route\n- **None**: Drops traffic\n\n**Use case:**\n- Force-tunnel traffic through a firewall\n- Route traffic between spokes through a hub NVA\n- Inspect outbound traffic\n\n**Configuration:**\n- Next Hop Type: VirtualAppliance\n- Next Hop IP Address: Private IP of the NVA\n\n*Exam tip*: VirtualAppliance = IP of the NVA (e.g., firewall). UDRs are needed for forced tunneling and hub routing.'

en['network-012.question'] = 'What is the main advantage of Private Link over Service Endpoints?'
en['network-012.option_a'] = 'Private Link is free'
en['network-012.option_b'] = 'Private Link provides private IP addresses for PaaS services'
en['network-012.option_c'] = 'Private Link has better performance'
en['network-012.option_d'] = 'Private Link supports more services'
en['network-012.explanation'] = '**Private Link** provides **private IP addresses** for PaaS services - the main advantage over Service Endpoints.\n\n**Private Link:**\n- Creates **Private Endpoints** with private IPs in the VNet\n- Traffic stays entirely within the Microsoft network\n- Access from on-premises via VPN/ExpressRoute also uses the private IP\n- Supports custom DNS configurations\n\n**Service Endpoints:**\n- Traffic stays on Azure backbone but uses the PaaS service\'s public IP\n- No private IP for the PaaS service\n- Accessible only from peered VNets (not from on-premises via ExpressRoute)\n\n**When to use what:**\n- Private Link: When you need a private IP for the PaaS service or on-premises access\n- Service Endpoints: Simpler setup when you only need VNet-to-PaaS access\n\n*Exam tip*: Private Link = private IP. Service Endpoints = traffic on Azure backbone, but uses service public IP.'

en['network-013.question'] = 'Which ExpressRoute SKU offers 99.95% SLA?'
en['network-013.option_a'] = 'Local'
en['network-013.option_b'] = 'Standard'
en['network-013.option_c'] = 'Premium'
en['network-013.option_d'] = 'All SKUs with redundant connections'
en['network-013.explanation'] = '**ExpressRoute SLA of 99.95%** requires **two circuits in different peering locations** - regardless of SKU.\n\n**ExpressRoute SKUs:**\n- **Local**: For Azure regions near the peering location, cheaper, limited regions\n- **Standard**: All regions in the same geopolitical area, no add-on cost\n- **Premium**: Global connectivity, more prefixes, added cost\n\n**SLA:**\n- Single circuit: 99.9% SLA (requires redundant connections within the circuit)\n- Two circuits at different peering locations: 99.95% SLA\n\n*Exam tip*: 99.95% SLA requires TWO circuits at DIFFERENT peering locations. Single circuit = 99.9%.'

en['network-014.question'] = 'Which features does Azure Front Door offer? (Select 3)'
en['network-014.option_a'] = 'Global load balancing with URL-based routing'
en['network-014.option_b'] = 'Web Application Firewall (WAF)'
en['network-014.option_c'] = 'SSL offloading and caching'
en['network-014.option_d'] = 'VPN Gateway functionality'
en['network-014.option_e'] = 'Virtual Machine orchestration'
en['network-014.explanation'] = '**Azure Front Door** is a global, scalable entry point for web applications.\n\n**Features:**\n1. **Global load balancing with URL-based routing**: Layer 7 routing, path-based, multi-region failover\n2. **Web Application Firewall (WAF)**: OWASP rules, custom rules, bot protection, rate limiting\n3. **SSL offloading and caching**: SSL termination at the edge, content caching for faster responses\n\n**Not included:**\n- **VPN Gateway functionality**: Use Azure VPN Gateway or Virtual WAN\n- **VM orchestration**: Use VM Scale Sets or AKS\n\n*Exam tip*: Front Door = global L7 LB + WAF + CDN. NOT VPN or VM orchestration.'

en['network-015.question'] = 'What is the difference between DDoS Infrastructure Protection and DDoS Network Protection?'
en['network-015.option_a'] = 'No difference, same service'
en['network-015.option_b'] = 'Infrastructure Protection is always active for free, Network Protection is paid'
en['network-015.option_c'] = 'Network Protection is always active'
en['network-015.option_d'] = 'Infrastructure Protection requires configuration'
en['network-015.explanation'] = '**DDoS Infrastructure Protection** is always active for free. **DDoS Network Protection** is a paid, enhanced tier.\n\n**DDoS Infrastructure Protection (Free):**\n- Always active on all Azure resources\n- Protects against common network-layer attacks\n- Automatic detection and mitigation\n\n**DDoS Network Protection (Paid):**\n- **$2,944/month** per 100 protected resources\n- Advanced attack detection and mitigation\n- Dedicated traffic monitoring and reporting\n- Access to DDoS Rapid Response (DRR) team\n- Custom mitigation policies\n- Integration with Azure Monitor and Security Center\n\n*Exam tip*: The free tier covers basic DDoS. For production-critical workloads requiring custom policies and reporting, use DDoS Network Protection.'

en['network-016.question'] = 'What is Azure NAT Gateway primarily used for?'
en['network-016.option_a'] = 'Inbound load balancing'
en['network-016.option_b'] = 'Outbound SNAT (Source Network Address Translation) for VMs'
en['network-016.option_c'] = 'VPN connectivity'
en['network-016.option_d'] = 'DNS resolution'
en['network-016.explanation'] = '**Azure NAT Gateway** provides **outbound SNAT** (Source Network Address Translation) for VMs in a VNet.\n\n**Purpose:**\n- Enables outbound internet connectivity for private VMs\n- Replaces default outbound access (which has limitations)\n- Provides static public IPs for outbound traffic\n\n**Key features:**\n- **Port exhaustion**: Prevents port exhaustion with 64,512 ports per SNAT IP\n- **Automatic scaling**: Up to 16 public IPs\n- **Zone resiliency**: Supports availability zones\n- **No outbound connectivity challenges**: Unpredictable or unreliable default outbound access\n\n**Not for:**\n- Inbound load balancing (use Load Balancer)\n- VPN connectivity (use VPN Gateway)\n- DNS resolution\n\n*Exam tip*: NAT Gateway = reliable outbound connectivity. Use when VMs need to reach the internet for updates, API calls, etc.'

en['network-017.question'] = 'What is Azure Route Server used for?'
en['network-017.option_a'] = 'DNS resolution for VNets'
en['network-017.option_b'] = 'Dynamic BGP route exchange between NVAs and VNets'
en['network-017.option_c'] = 'Load balancing traffic'
en['network-017.option_d'] = 'Traffic filtering'
en['network-017.explanation'] = '**Azure Route Server** enables dynamic **BGP route exchange** between Network Virtual Appliances (NVAs) and Azure VNets.\n\n**Purpose:**\n- Exchange BGP routes with NVAs (firewalls, routers)\n- Replace static UDRs with dynamic routing\n- Automatically propagate NVA-learned routes to the VNet\n\n**How it works:**\n1. Deploy Route Server in a VNet\n2. Configure BGP peering with your NVA\n3. Route Server learns routes from the NVA\n4. Routes are propagated to all VMs in the VNet\n\n**Benefits:**\n- No need to manage UDRs manually\n- NVA changes propagate automatically\n- Supports NVAs from different vendors\n\n*Exam tip*: Route Server = BGP between NVAs and Azure. Simplifies routing with dynamic route exchange.'

en['network-018.question'] = 'What is the main advantage of Azure Virtual WAN?'
en['network-018.option_a'] = 'Lower cost than individual network resources'
en['network-018.option_b'] = 'Hub-and-spoke topology with automated branch connectivity'
en['network-018.option_c'] = 'Higher bandwidth than ExpressRoute'
en['network-018.option_d'] = 'Built-in DDoS protection'
en['network-018.explanation'] = '**Azure Virtual WAN** provides a **hub-and-spoke topology** with automated branch connectivity.\n\n**Main advantage:**\n- Automates the creation of a hub-and-spoke network\n- Built-in connectivity for branches (VPN, ExpressRoute, SD-WAN)\n- Centralized management of network policies\n\n**Features:**\n- **VPN connectivity**: Site-to-site, Point-to-site\n- **ExpressRoute connectivity**: Gateway integration\n- **SD-WAN integration**: Automated partner device configuration\n- **Firewall integration**: Azure Firewall in the hub\n- **Virtual Network connections**: Connect spoke VNets\n\n**Benefits:**\n- Reduces operational complexity\n- Automates routing and connectivity\n- Built-in redundancy and HA\n\n*Exam tip*: Virtual WAN = managed hub-and-spoke. Best for organizations with many branches and complex connectivity needs.'

en['network-019.question'] = 'Where are NSG Flow Logs stored?'
en['network-019.option_a'] = 'Azure SQL Database'
en['network-019.option_b'] = 'Azure Storage Account'
en['network-019.option_c'] = 'Azure Cache for Redis'
en['network-019.option_d'] = 'Azure Cosmos DB'
en['network-019.explanation'] = '**NSG Flow Logs** are stored in an **Azure Storage Account**.\n\n**How it works:**\n- Flow logs are written to a Storage Account as blobs\n- A **Network Watcher** must be enabled in the region\n- The target storage account must be in the same region\n\n**Log contents:**\n- Source/destination IP and port\n- Protocol, direction\n- Packets and bytes transferred\n- Decision (Allowed/Denied)\n\n**Retention:**\n- Configurable retention (1-365 days)\n- Or use Traffic Analytics for longer-term analysis\n\n**Limitations:**\n- Storage Account must be in the same region as the NSG\n- Flow logs cannot be stored in a storage account behind a firewall without exception\n\n*Exam tip*: NSG Flow Logs → Storage Account. For analysis: enable Traffic Analytics (Log Analytics).'

en['network-020.question'] = 'What is Azure Firewall Manager used for?'
en['network-020.option_a'] = 'Central management of Azure Firewalls across multiple hubs'
en['network-020.option_b'] = 'Local firewall configuration on VMs'
en['network-020.option_c'] = 'DDoS protection management'
en['network-020.option_d'] = 'VPN device management'
en['network-020.explanation'] = '**Azure Firewall Manager** enables **central management** of Azure Firewalls across multiple hubs and Virtual WANs.\n\n**Features:**\n- Manage multiple firewalls from a single pane\n- Create and apply firewall policies across hubs\n- Monitor firewall health and activity\n- Integrate with Virtual WAN and hub VNets\n\n**Capabilities:**\n- **Central policy management**: Create once, apply to many\n- **Security administration**: Role-based access to firewall management\n- **Third-party Security as a Service** (SaaS): Integrate with partners\n- **Hub virtual network**: Deploy and manage hub infrastructure\n\n**Use cases:**\n- Enterprise with multiple regions and firewalls\n- Managed Service Providers (MSPs)\n- Organizations with Azure Virtual WAN\n\n*Exam tip*: Firewall Manager = centralized policy management for Azure Firewall across multiple instances/hubs.'

# monitor-008 through monitor-019
en['monitor-008.question'] = 'What are Azure Monitor Workbooks used for?'
en['monitor-008.option_a'] = 'Interactive data visualization and reporting'
en['monitor-008.option_b'] = 'Automated VM patch management'
en['monitor-008.option_c'] = 'Network traffic analysis'
en['monitor-008.option_d'] = 'Database query execution'
en['monitor-008.explanation'] = '**Azure Monitor Workbooks** provide **interactive data visualization and reporting**.\n\n**Features:**\n- Combine text, metrics, logs, and parameters\n- Create rich, interactive reports\n- Share with teams as dashboards\n\n**Key capabilities:**\n- **Multiple data sources**: Metrics, Logs, Resource Graph\n- **Interactive controls**: Dropdowns, sliders, filters\n- **Templates**: Pre-built workbooks for common scenarios\n- **Customization**: Fully customizable with KQL and Markdown\n\n**Use cases:**\n- Performance dashboards\n- Compliance reports\n- Operational runbooks\n- Root cause analysis\n\n*Exam tip*: Workbooks = interactive reports and dashboards. More powerful than standard Dashboards (supports KQL, parameters, conditional display).'

en['monitor-009.question'] = 'What changes does Azure Change Tracking track on VMs?'
en['monitor-009.option_a'] = 'CPU and memory usage'
en['monitor-009.option_b'] = 'Software, files, registry, and services changes'
en['monitor-009.option_c'] = 'Network packet loss'
en['monitor-009.option_d'] = 'Disk IO operations'
en['monitor-009.explanation'] = '**Azure Change Tracking** monitors changes to **software, files, registry, and services** on VMs.\n\n**Tracked categories:**\n\n1. **Software**: Installed applications and updates\n2. **Files**: Changes to monitored files and folders\n3. **Registry**: Registry key/value changes\n4. **Services**: Windows service state changes (running/stopped)\n\n**How it works:**\n- Uses Log Analytics agent\n- Sends change data to Log Analytics workspace\n- Integrates with Azure Automation and Update Management\n\n**Use cases:**\n- Security auditing\n- Compliance monitoring\n- Troubleshooting (identify what changed)\n- Drift detection\n\n*Exam tip*: Change Tracking = software, files, registry, services. NOT performance metrics (CPU, memory, disk, network).'

en['monitor-010.question'] = 'Which agent is required for VM Insights?'
en['monitor-010.option_a'] = 'Azure Monitor Agent only'
en['monitor-010.option_b'] = 'Dependency Agent AND Azure Monitor Agent (or Log Analytics Agent)'
en['monitor-010.option_c'] = 'Diagnostics Extension only'
en['monitor-010.option_d'] = 'Linux Monitoring Agent only'
en['monitor-010.explanation'] = '**VM Insights** requires **two agents**: the Dependency Agent AND Azure Monitor Agent (or legacy Log Analytics Agent).\n\n**Required agents:**\n1. **Dependency Agent**: Maps VM dependencies and processes (network connections, process details)\n2. **Azure Monitor Agent (AMA)** or **Log Analytics Agent (MMA)**: Collects performance metrics, event logs, and custom data\n\n**What VM Insights provides:**\n- **Performance charts**: CPU, memory, disk, network\n- **Dependency map**: Visual map of VM connections and processes\n- **Health monitoring**: VM health state and alerts\n\n**Onboarding:**\n- VM Insights can enable both agents automatically\n- Manual installation also possible\n\n*Exam tip*: VM Insights = Dependency Agent + AMA/MMA. Dependency Agent = process/connection mapping. AMA/MMA = performance data collection.'

en['monitor-011.question'] = 'Which metrics does Container Insights collect for AKS?'
en['monitor-011.option_a'] = 'Only node-level metrics'
en['monitor-011.option_b'] = 'Metrics from controllers, nodes, and containers'
en['monitor-011.option_c'] = 'Only application-level metrics'
en['monitor-011.option_d'] = 'Only storage metrics'
en['monitor-011.explanation'] = '**Container Insights** collects metrics from **controllers, nodes, and containers** for AKS.\n\n**Collected metrics:**\n\n1. **Node level**: CPU, memory, disk, network per node\n2. **Controller level**: Deployment/StatefulSet/DaemonSet resource usage\n3. **Container level**: Per-container CPU, memory, filesystem\n4. **Kubernetes objects**: Pod counts, replicas, conditions\n\n**How it works:**\n- Uses a containerized version of the Log Analytics agent\n- Deployed as a DaemonSet on the AKS cluster\n- Sends data to Log Analytics workspace\n\n**Features:**\n- Live monitoring dashboard\n- Performance alerts\n- Interactive KQL queries\n\n*Exam tip*: Container Insights = full-stack monitoring (node → controller → container). Deployed as a DaemonSet in AKS.'

en['monitor-012.question'] = 'Which notification types do Action Groups support? (Select 3)'
en['monitor-012.option_a'] = 'Email'
en['monitor-012.option_b'] = 'SMS'
en['monitor-012.option_c'] = 'Push notification (to Azure mobile app)'
en['monitor-012.option_d'] = 'Teams message'
en['monitor-012.option_e'] = 'Fax'
en['monitor-012.explanation'] = '**Action Groups** support multiple notification types:\n\n**Supported types (the three correct ones):**\n1. **Email**: Send to Azure Active Directory users or email addresses\n2. **SMS**: To phone numbers (carrier-dependent)\n3. **Push notification**: To the Azure mobile app\n\n**Also supported (not among the correct answers):**\n- Voice call\n- Webhook\n- ITSM connector\n- Automation Runbook\n- Logic App\n- Function\n\n**Not supported:**\n- **Teams message**: Requires a custom connector (not native Action Group)\n- **Fax**: Not supported\n\n*Exam tip*: Action Groups = Email, SMS, Push, Voice, Webhook, ITSM, Automation, Logic App, Function. Teams is NOT native.'

en['monitor-013.question'] = 'What is the main advantage of Data Collection Rules (DCR) over legacy data collection?'
en['monitor-013.option_a'] = 'Centralized configuration for data collection across resources'
en['monitor-013.option_b'] = 'Lower cost'
en['monitor-013.option_c'] = 'Faster data transfer'
en['monitor-013.option_d'] = 'No agent required'
en['monitor-013.explanation'] = '**Data Collection Rules (DCR)** provide **centralized configuration** for data collection across resources.\n\n**DCR advantages:**\n- **Centralized management**: Define collection rules once, apply to multiple resources\n- **Separation of concerns**: Collection config is separate from workspace\n- **Flexible transformations**: Use Data Collection Transformations (DCT) to filter/modify data\n- **Consistent configuration**: Same rules applied across all resources\n\n**Legacy approach:**\n- Per-resource configuration in Diagnostic Settings\n- No central management\n- Hard to maintain consistency at scale\n\n**DCR components:**\n- Data sources (what to collect)\n- Destinations (where to send)\n- Transformations (how to process)\n- Associations (which resources use this rule)\n\n*Exam tip*: DCR = centralized, scalable data collection. The future of Azure Monitor data collection.'

en['monitor-014.question'] = 'Which categories does Azure Advisor offer? (Select 3)'
en['monitor-014.option_a'] = 'Cost'
en['monitor-014.option_b'] = 'Security'
en['monitor-014.option_c'] = 'Reliability'
en['monitor-014.option_d'] = 'Compliance'
en['monitor-014.option_e'] = 'User Management'
en['monitor-014.explanation'] = '**Azure Advisor** provides recommendations in five categories:\n\n**The three correct ones:**\n1. **Cost**: Right-sizing, Reserved Instances, savings opportunities\n2. **Security**: Security hardening, missing protections\n3. **Reliability**: High availability, backups, disaster recovery\n\n**Additional categories (not among the answers):**\n- **Performance**: Speed optimization, latency reduction\n- **Operational Excellence**: Stability, deployment best practices\n\n**Not an Advisor category:**\n- **Compliance**: Uses Azure Policy, not Advisor\n- **User Management**: Not a thing in Advisor\n\n*Exam tip*: Advisor categories: Cost, Security, Reliability, Performance, Operational Excellence. (5 total)'

en['monitor-015.question'] = 'Which Azure resources do NOT support Autoscale?'
en['monitor-015.option_a'] = 'VM Scale Sets'
en['monitor-015.option_b'] = 'App Service (Web Apps)'
en['monitor-015.option_c'] = 'Individual Azure VMs'
en['monitor-015.option_d'] = 'Azure Spring Apps'
en['monitor-015.explanation'] = '**Individual Azure VMs** do NOT support Autoscale.\n\n**Resources that support Autoscale:**\n- **VM Scale Sets**: Autoscale based on metrics or schedule\n- **App Service (Web Apps)**: Standard plan and higher\n- **Azure Spring Apps**: Autoscale for microservice apps\n- **Cloud Services (classic)**: Autoscale roles\n- **Azure Data Explorer**: Autoscale instances\n\n**Resources that do NOT support Autoscale:**\n- **Individual VMs**: Scale only via manual resize or automation (Azure Automation)\n- **Azure SQL Database**: Supports DTU scaling but not traditional Autoscale (serverless tier scales automatically but differently)\n\n*Exam tip*: Individual VMs = no Autoscale. You need VM Scale Sets or automation logic (Runbooks, Logic Apps) to scale single VMs.'

en['monitor-016.question'] = 'What is the difference between Azure Service Health and Resource Health?'
en['monitor-016.option_a'] = 'No difference'
en['monitor-016.option_b'] = 'Service Health shows service-wide issues, Resource Health shows individual resource status'
en['monitor-016.option_c'] = 'Resource Health is always more detailed'
en['monitor-016.option_d'] = 'Service Health is only for VMs'
en['monitor-016.explanation'] = '**Azure Service Health** and **Resource Health** serve different purposes:\n\n**Azure Service Health:**\n- Shows *service-wide* issues affecting your subscription\n- **Service Issues**: Problems with Azure services (e.g., "Storage down in West Europe")\n- **Planned Maintenance**: Upcoming changes that may affect you\n- **Health Advisories**: Subscription-level recommendations\n\n**Azure Resource Health:**\n- Shows *individual resource* status\n- For each resource: Is it healthy or degraded?\n- Provides cause and resolution information per resource\n- Historical health data\n\n**Combined:**\n- Service Health = "Is Storage broken in my region?"\n- Resource Health = "Is THIS SPECIFIC storage account healthy?"\n\n*Exam tip*: Service Health = subscription/services. Resource Health = individual resources.'

en['monitor-017.question'] = 'What does Application Insights Smart Detection automatically detect?'
en['monitor-017.option_a'] = 'Anomalies in telemetry patterns (failure spikes, performance drops)'
en['monitor-017.option_b'] = 'Manual code changes'
en['monitor-017.option_c'] = 'SQL injection attacks'
en['monitor-017.option_d'] = 'Unauthorized access attempts'
en['monitor-017.explanation'] = '**Application Insights Smart Detection** automatically detects **anomalies in telemetry patterns**.\n\n**Detected anomalies:**\n1. **Failure anomalies**: Sudden increase in failed requests, exceptions\n2. **Performance anomalies**: Degradation in response times, slow page load\n3. **Dependency anomalies**: Failures or slowdowns in external dependencies\n4. **Trace anomalies**: Changes in trace severity distribution\n\n**How it works:**\n- Uses machine learning models\n- Dynamically establishes baseline behavior\n- Detects deviations from the baseline\n- Sends alerts via Action Groups\n\n**Not for:**\n- **Code changes**: Use Application Insights Analytics or git\n- **SQL injection**: Use WAF or Security Center\n- **Unauthorized access**: Use Azure AD logs or Security Center\n\n*Exam tip*: Smart Detection = ML-powered anomaly detection. No manual threshold configuration needed.'

en['monitor-018.question'] = 'What are Query Packs in Log Analytics used for?'
en['monitor-018.option_a'] = 'Storing query results permanently'
en['monitor-018.option_b'] = 'Organizing and sharing KQL queries across workspaces'
en['monitor-018.option_c'] = 'Optimizing query performance'
en['monitor-018.option_d'] = 'Backing up Log Analytics data'
en['monitor-018.explanation'] = '**Query Packs** organize and share **KQL queries across Log Analytics workspaces**.\n\n**Purpose:**\n- Save and organize useful KQL queries\n- Share queries with team members\n- Group related queries (e.g., "Security queries", "Performance queries")\n\n**Features:**\n- Queries are stored in the pack, not in a specific workspace\n- Can be used across multiple workspaces\n- Support version control and description\n- Built-in packs: Security, Performance, etc.\n\n**How it works:**\n1. Create a Query Pack\n2. Add KQL queries with descriptions\n3. Share the pack with team members\n4. Access queries from any Log Analytics workspace\n\n*Exam tip*: Query Packs = KQL query library. Share and organize queries across workspaces. Not for storing results.'

en['monitor-019.question'] = 'What is Azure Monitor Private Link Scope (AMPLS) used for?'
en['monitor-019.option_a'] = 'Connecting workspaces to a Private Endpoint for network isolation'
en['monitor-019.option_b'] = 'Linking multiple Log Analytics workspaces for federated queries'
en['monitor-019.option_c'] = 'Encrypting Log Analytics data at rest'
en['monitor-019.option_d'] = 'Replicating Log Analytics data across regions'
en['monitor-019.explanation'] = '**Azure Monitor Private Link Scope (AMPLS)** connects **Log Analytics workspaces and Application Insights resources** to a **Private Endpoint** for network isolation.\n\n**Purpose:**\n- Access Log Analytics and Application Insights over a Private Endpoint\n- Data never traverses the public internet\n- Network isolation for compliance\n\n**How it works:**\n1. Create an AMPLS resource\n2. Add Log Analytics workspaces and App Insights resources to the scope\n3. Create a Private Endpoint in your VNet and link it to AMPLS\n4. All traffic to the scoped resources uses the Private Endpoint\n\n**Benefits:**\n- Data exfiltration prevention\n- Compliance with network isolation requirements\n- Works with on-premises via ExpressRoute\n\n*Exam tip*: AMPLS = Private Endpoint for Azure Monitor resources. Combines multiple workspaces into one Private Endpoint.'

# compute-021 through compute-025 (App Service focused)
en['compute-021.question'] = 'Which Azure component is required for a custom SSL/TLS certificate on an App Service Web App?'
en['compute-021.option_a'] = 'Azure Key Vault'
en['compute-021.option_b'] = 'Azure DNS'
en['compute-021.option_c'] = 'Azure Front Door'
en['compute-021.option_d'] = 'Azure CDN'
en['compute-021.explanation'] = '**Azure Key Vault** is required to store and serve custom SSL/TLS certificates for App Service.\n\n**How it works:**\n1. Store certificate in **Azure Key Vault**\n2. Configure App Service to use the Key Vault certificate\n3. App Service will automatically renew if using Key Vault\n\n**Other options:**\n- **App Service Managed Certificate**: Free option for custom domains (no Key Vault needed, but limited)\n- **Azure Front Door**: Can offload SSL, but not required for basic SSL\n\n**Requirements:**\n- Key Vault access policy must grant App Service read access\n- Certificate must be in PFX format\n- Private key must be exportable\n\n*Exam tip*: Key Vault = secure certificate storage and auto-renewal. App Service Managed Certificate = free option without KV.'

en['compute-022.question'] = 'You want to use a custom DNS name (e.g., www.app.example.com) for an App Service Web App. What must you do?'
en['compute-022.option_a'] = 'Nothing, custom domains are automatic'
en['compute-022.option_b'] = 'Create a CNAME or A record pointing to the App Service domain, then validate in App Service'
en['compute-022.option_c'] = 'Only register the domain with a registrar'
en['compute-022.option_d'] = 'Create a Traffic Manager profile'
en['compute-022.explanation'] = 'To use a custom DNS name with App Service:\n\n**Required steps:**\n1. **Create a DNS record** (CNAME for www, A record for root domain) pointing to `yourapp.azurewebsites.net`\n2. **Validate domain ownership** in the Azure Portal (App Service → Custom Domains)\n3. **Upload/bind certificate** for HTTPS (if needed)\n\n**Record types:**\n- **CNAME**: For subdomains (www, api, app)\n- **A record**: For root domain (example.com) - requires the verified custom domain\n- **TXT record**: For domain verification (used by Azure to prove ownership)\n\n**Requirements:**\n- App Service plan must be **Basic tier or higher** for custom domains\n- Free/Shared tier does NOT support custom domains\n\n*Exam tip*: Custom domain = DNS record + domain validation in App Service. Requires Basic tier or higher.'

en['compute-023.question'] = 'Which statements about the App Service Backup feature are correct? (Select 2)'
en['compute-023.option_a'] = 'Backups can be saved to a Storage Account container'
en['compute-023.option_b'] = 'Backups are automatically enabled by default'
en['compute-023.option_c'] = 'Backups include app configuration and file content'
en['compute-023.option_d'] = 'Backups can be restored to a different App Service'
en['compute-023.explanation'] = '**App Service Backup** features:\n\n**Correct statements:**\n1. **Backups can be saved to a Storage Account container**: You configure a Storage Account as the backup destination\n2. **Backups include app configuration and file content**: The full app state (both app content and settings) is backed up\n\n**Incorrect statements:**\n- **Backups are automatically enabled**: You must manually configure backups (not automatic)\n- **Backups can be restored to a different App Service**: Restore is supported, but some limitations apply (target must be in the same App Service Plan tier)\n\n**Requirements:**\n- App Service Standard tier or higher\n- A Storage Account in the same subscription\n\n*Exam tip*: App Service Backup = configurable, to Storage Account, includes config + files. Requires Standard+ plan.'

en['compute-024.question'] = 'Which networking features can you configure for an Azure App Service Web App? (Select 2)'
en['compute-024.option_a'] = 'Regional VNet Integration'
en['compute-024.option_b'] = 'Access Restrictions (IP whitelist)'
en['compute-024.option_c'] = 'Site-to-Site VPN'
en['compute-024.option_d'] = 'ExpressRoute Gateway'
en['compute-024.explanation'] = '**App Service networking features:**\n\n**Correct features:**\n1. **Regional VNet Integration**: Allows the web app to access resources in a VNet (Premium V2/V3+)\n   - Outbound traffic from the app goes through the VNet\n   - Can access VNet-internal resources\n\n2. **Access Restrictions (IP whitelist)**: Restrict inbound traffic based on source IP\n   - Allow only certain IP ranges\n   - Works at the app/App Service level\n\n**Not available:**\n- **Site-to-Site VPN**: App Service cannot be a VPN endpoint, but can access VPN-connected resources via VNet Integration\n- **ExpressRoute Gateway**: App Service does not have its own ER gateway\n\n*Exam tip*: App Service = VNet Integration (outbound) + Access Restrictions (inbound). No VPN/ER Gateway on the app itself.'

en['compute-025.question'] = 'You want your Azure App Service Web App to automatically scale horizontally. Which configuration is required?'
en['compute-025.option_a'] = 'Enable Auto-Scaling in the App Service Plan settings'
en['compute-025.option_b'] = 'Enable Auto-Scaling on the App Service Web App directly'
en['compute-025.option_c'] = 'Create a front-end load balancer'
en['compute-025.option_d'] = 'Deploy multiple App Service Plans manually'
en['compute-025.explanation'] = (
    'To enable **automatic horizontal scaling** for an App Service:\n'
    '**Correct approach:**\n'
    '1. The App Service Plan must be at least **Standard tier**\n'
    '2. **Enable Auto-Scaling in the App Service Plan settings**\n'
    '   - Auto-Scaling is configured on the *plan*, not the *app*\n'
    '   - Scale out: Add more instances of the plan\n'
    '   - Scale conditions: CPU > 70%, Memory > 80%, HTTP Queue > 100\n'
    '\n'
    '**Why not on the app directly?**\n'
    '- The App Service Plan is the container for instances\n'
    '- Scaling the plan affects ALL apps in that plan\n'
    '- Auto-Scaling at the plan level adds more VM instances\n'
    '\n'
    '**Manual alternatives:**\n'
    '- Manually change the plan instance count\n'
    '- Scheduled scaling for predictable patterns\n'
    '\n'
    '*Exam tip*: Auto-Scaling is configured on the App Service Plan.'
)

